  `discussion_prompt` text COMMENT '함께 생각해봐요 질문',
  `summary` varchar(255) DEFAULT NULL,
  `mate_type_code` varchar(20) DEFAULT NULL,
  `mate_reason` text,
  PRIMARY KEY (`code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='진단 결과 유형별 명칭, 설명, 가이드라인';
