CREATE TABLE `factor_descriptions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `factor` varchar(50) NOT NULL COMMENT '요인 구분 (risk, benefit, justice)',
  `rank` varchar(10) NOT NULL COMMENT '수준 등급 (상, 중, 하)',
  `description` text NOT NULL COMMENT '설명글',
  PRIMARY KEY (`id`),
  KEY `ix_factor_descriptions_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='요인별 수준(상/중/하)에 대한 분석 설명';
