/*!40000 ALTER TABLE `factor_descriptions` DISABLE KEYS */;
INSERT INTO `factor_descriptions` VALUES (10,'risk','상','인공지능 기술의 오남용, 프라이버시 침해, 알고리즘 편향성, \n일자리 대체 등 잠재적 부작용과 위험성에 대해 매우 민감하게 경계하고 있습니다. \nAI 도입 시 철저한 검증과 강력한 통제 및 안전장치가 필수적이라고 판단합니다.'),(11,'benefit','상','AI 기술이 개인의 생산성 향상, 비즈니스 혁신, \n일상적 편리함에 있어 막대한 긍정적 변화를 가져다줄 것으로 굳게 신뢰하고 있으며, \n새로운 AI 도구를 실생활과 업무에 신속하고 적극적으로 수용하고자 합니다.'),(12,'justice','상','AI 기술의 혜택과 성과가 일부 대기업이나 특정 특권층에 집중되지 않고, \n디지털 약자 보호 및 사회적 불평등 해소에 기여해야 한다고 강력히 생각합니다. \n기술 민주화와 공정한 분배, 제도적 안전망 구축을 지지합니다.'),(13,'risk','중','AI 기술이 유발할 수 있는 부작용과 한계를 적절히 인지하고 있으나, \n극단적인 거부감보다는 현실적인 조율과 관리 체계 마련을 통해 해결할 수 있다고 봅니다. \n위험과 기회 사이에서 비교적 균형 잡힌 관점을 유지합니다.'),(14,'benefit','중','AI가 제공하는 실용성과 효율성을 인정하지만, \n그것이 인류의 삶을 완전히 혁신할 것이라 과도하게 기대하기보다는\n 필요에 따라 유용하게 활용할 수 있는 일상적 보조 도구 수준으로 인식합니다.'),(15,'justice','중','기술 발전 과정에서 공정성과 사회적 책임이 중요하다는 일반론적 가치에 동의하며,\n 급격한 규제보다는 사회 구성원 간의 점진적인 대화와 논의를 통한 합의 형성이 바람직하다고 봅니다.'),(16,'risk','하','AI 기술의 위험성이나 윤리적 위협 요소를 크게 우려하지 않는 편입니다. \n기술 개발 및 발전 과정에서 발생할 수 있는 일시적 부작용이나 오류는 기술의 고도화를 통해 \n자연스럽게 해결될 수 있다고 믿습니다.'),(17,'benefit','하','AI 기술이 주는 혜택이나 편리함을 크게 체감하지 못하며 다소 유보적인 입장을 취합니다. \n기존 방식에 비해 혁신적인 이점이 크지 않다고 보거나, \nAI 기술 없이도 일상과 업무를 충분히 효과적으로 영위할 수 있다고 판단합니다.'),(18,'justice','하','AI 기술의 사회적 영향력이나 분배 정의에 중점을 두기보다는, 시장의 자율성과 개인의 선택권을 더 중시합니다. \n불필요한 제도적 규제를 최소화하고 기술 혁신과 성장을 최우선으로 유도하는 것이 장기적으로 유익하다고 판단합니다.');
/*!40000 ALTER TABLE `factor_descriptions` ENABLE KEYS */;
