--
-- Table structure for table `respondents`
--

DROP TABLE IF EXISTS `respondents`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `respondents` (
  `id` int NOT NULL AUTO_INCREMENT,
  `consent` tinyint(1) NOT NULL COMMENT 'Q1 설문 참여 동의 여부',
  `gender` varchar(10) DEFAULT NULL,
  `gender_other` varchar(100) DEFAULT NULL COMMENT 'Q2 성별 기타 직접입력',
  `school_level` varchar(10) DEFAULT NULL,
  `school_name` varchar(200) DEFAULT NULL COMMENT 'Q4 소속 학교명',
  `grade` smallint DEFAULT NULL COMMENT 'Q5 학년 (1~3)',
  `school_ai_policy` varchar(10) DEFAULT NULL,
  `pre_q7` smallint DEFAULT NULL COMMENT 'Q7 평소 생성형 AI 사용 빈도 (1=전혀~5=매우)',
  `pre_q8` smallint DEFAULT NULL COMMENT 'Q8 AI 학습 경험 여부 (1=전혀~5=매우)',
  `pre_q9` smallint DEFAULT NULL COMMENT 'Q9 AI 윤리 학습 경험 여부 (1=전혀~5=매우)',
  `created_at` datetime DEFAULT (now()),
  `is_pilot` tinyint(1) NOT NULL DEFAULT '0',
  `basic_responses` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_respondents_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2221 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='응답자 기본 인구통계 및 사전 인식 데이터';
/*!40101 SET character_set_client = @saved_cs_client */;

