  `q16` smallint DEFAULT NULL COMMENT 'AI 정의로운 사회 기여',
  `created_at` datetime DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `respondent_id` (`respondent_id`),
  KEY `ix_survey_responses_id` (`id`),
  CONSTRAINT `survey_responses_ibfk_1` FOREIGN KEY (`respondent_id`) REFERENCES `respondents` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3414 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='AI 인식 16문항 리커트 응답';
